        System.out.println(symbol);
    }
}

Empty statements (just the semicolon) are also allowed in java, therefore below code is also legal:
public class Test {
    public static void main(String [] args) {
        System.out.println("Hello");
        ;
        ;
        ;
        ;
        ;
        ;
        ;
        ;
    }
}

